import type * as DMMF from '@prisma/dmmf'

/** Maps a Prisma scalar type name to the equivalent TypeScript type. */
function scalarToTsType(fieldType: string): string {
  switch (fieldType) {
    case 'Int':
    case 'Float':
    case 'Decimal':
      return 'number'
    case 'BigInt':
      return 'bigint'
    case 'Boolean':
      return 'boolean'
    case 'DateTime':
      return 'Date'
    case 'Bytes':
      return 'Uint8Array'
    case 'Json':
      return 'unknown'
    case 'String':
    default:
      return 'string'
  }
}

/** Converts a DMMF field to its TypeScript type annotation, including list and nullability modifiers. */
function fieldToTsType(field: DMMF.Field): string {
  let type: string

  if (field.kind === 'scalar') {
    type = scalarToTsType(field.type)
  } else if (field.kind === 'enum' || field.kind === 'object') {
    type = field.type
  } else {
    type = 'unknown'
  }

  if (field.isList) {
    type = `${type}[]`
  }

  if (!field.isRequired) {
    type = `${type} | null`
  }

  return type
}

/** Renders a TypeScript enum declaration from a DMMF enum definition. */
export function renderEnum(dmmfEnum: DMMF.DatamodelEnum): string {
  const values = dmmfEnum.values.map((v) => `  ${v.name} = '${v.name}',`).join('\n')
  return `export enum ${dmmfEnum.name} {\n${values}\n}`
}

/** Renders a TypeScript interface for a Prisma model, covering all fields. */
export function renderModelInterface(model: DMMF.Model): string {
  const fields = model.fields
    .map((f) => {
      const optional = !f.isRequired ? '?' : ''
      return `  ${f.name}${optional}: ${fieldToTsType(f)}`
    })
    .join('\n')
  return `export interface ${model.name} {\n${fields}\n}`
}

/** Renders a TypeScript interface for the create-input payload of a model. */
export function renderCreateInput(model: DMMF.Model): string {
  const scalarFields = model.fields.filter((f) => f.kind === 'scalar' && !f.isReadOnly && !f.isGenerated)
  const fields = scalarFields
    .map((f) => {
      const optional = !f.isRequired || f.hasDefaultValue ? '?' : ''
      return `  ${f.name}${optional}: ${scalarToTsType(f.type)}`
    })
    .join('\n')
  return `export interface ${model.name}CreateInput {\n${fields}\n}`
}

/** Renders a TypeScript interface for the update-input payload of a model (all fields optional). */
export function renderUpdateInput(model: DMMF.Model): string {
  const scalarFields = model.fields.filter((f) => f.kind === 'scalar' && !f.isReadOnly && !f.isGenerated)
  const fields = scalarFields.map((f) => `  ${f.name}?: ${scalarToTsType(f.type)}`).join('\n')
  return `export interface ${model.name}UpdateInput {\n${fields}\n}`
}

/** Renders a typed REST API client class for a single Prisma model. */
export function renderClient(model: DMMF.Model): string {
  const name = model.name
  const resourcePath = name.toLowerCase()
  const idField = model.fields.find((f) => f.isId)
  const idType = idField ? scalarToTsType(idField.type) : 'string'
  const idName = idField?.name ?? 'id'

  return `export class ${name}Client {
  constructor(private readonly baseUrl: string) {}

  async findMany(): Promise<${name}[]> {
    const res = await fetch(\`\${this.baseUrl}/${resourcePath}\`)
    return res.json() as Promise<${name}[]>
  }

  async findUnique(${idName}: ${idType}): Promise<${name} | null> {
    const res = await fetch(\`\${this.baseUrl}/${resourcePath}/\${${idName}}\`)
    if (res.status === 404) return null
    return res.json() as Promise<${name}>
  }

  async create(data: ${name}CreateInput): Promise<${name}> {
    const res = await fetch(\`\${this.baseUrl}/${resourcePath}\`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    })
    return res.json() as Promise<${name}>
  }

  async update(${idName}: ${idType}, data: ${name}UpdateInput): Promise<${name}> {
    const res = await fetch(\`\${this.baseUrl}/${resourcePath}/\${${idName}}\`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    })
    return res.json() as Promise<${name}>
  }

  async delete(${idName}: ${idType}): Promise<void> {
    await fetch(\`\${this.baseUrl}/${resourcePath}/\${${idName}}\`, { method: 'DELETE' })
  }
}`
}

/** Renders the complete generated TypeScript file content for all models and enums in the DMMF. */
export function renderFile(dmmf: { datamodel: DMMF.Datamodel }): string {
  const sections: string[] = [
    '// This file was auto-generated by @prisma/generator-rest-client. Do not edit by hand.',
    '',
  ]

  for (const dmmfEnum of dmmf.datamodel.enums) {
    sections.push(renderEnum(dmmfEnum))
    sections.push('')
  }

  for (const model of dmmf.datamodel.models) {
    sections.push(renderModelInterface(model))
    sections.push('')
    sections.push(renderCreateInput(model))
    sections.push('')
    sections.push(renderUpdateInput(model))
    sections.push('')
    sections.push(renderClient(model))
    sections.push('')
  }

  return sections.join('\n')
}

